+fn sanitize_hint_extension(value: &str) -> Option<String> {
+    let trimmed = value.trim_start_matches('.').trim();
+    if trimmed.is_empty() {
+        return None;
+    }
+    if trimmed
+        .chars()
+        .all(|ch| ch.is_ascii_alphanumeric() || ch == '-' || ch == '_')
+    {
+        Some(trimmed.to_owned())
+    } else {
+        None
+    }
+}
